const express = require('express');
const session = require('express-session');
const twilio = require('twilio');
const crypto = require('crypto');

const app = express();

app.use(express.json());
app.use(express.urlencoded({ extended: true }));

app.use(
  session({
    secret: process.env.SESSION_SECRET || 'replace-with-a-strong-secret',
    resave: false,
    saveUninitialized: false,
    cookie: {
      httpOnly: true,
      secure: process.env.NODE_ENV === 'production',
      sameSite: 'lax',
      maxAge: 15 * 60 * 1000
    }
  })
);

const twilioClient =
  process.env.TWILIO_ACCOUNT_SID && process.env.TWILIO_AUTH_TOKEN
    ? twilio(process.env.TWILIO_ACCOUNT_SID, process.env.TWILIO_AUTH_TOKEN)
    : null;

const OTP_TTL_MS = 5 * 60 * 1000;
const MAX_VERIFY_ATTEMPTS = 5;

function generateOtp() {
  return String(Math.floor(100000 + Math.random() * 900000));
}

function hashOtp(otp, salt) {
  return crypto.createHmac('sha256', salt).update(String(otp)).digest('hex');
}

function now() {
  return Date.now();
}

function ensureAuthSession(req) {
  if (!req.session.otp) req.session.otp = {};
  return req.session.otp;
}

async function sendSms(to, message) {
  if (!twilioClient) {
    console.log(`[SMS MOCK] To: ${to} | Message: ${message}`);
    return;
  }

  const from = process.env.TWILIO_PHONE_NUMBER;
  if (!from) throw new Error('TWILIO_PHONE_NUMBER is required');

  await twilioClient.messages.create({
    from,
    to,
    body: message
  });
}

app.post('/auth/2fa/request', async (req, res) => {
  try {
    const { userId, phoneNumber } = req.body;

    if (!userId || !phoneNumber) {
      return res.status(400).json({ error: 'userId and phoneNumber are required' });
    }

    const otp = generateOtp();
    const salt = crypto.randomBytes(16).toString('hex');
    const otpHash = hashOtp(otp, salt);

    const otpSession = ensureAuthSession(req);
    otpSession.userId = String(userId);
    otpSession.phoneNumber = String(phoneNumber);
    otpSession.otpHash = otpHash;
    otpSession.salt = salt;
    otpSession.createdAt = now();
    otpSession.expiresAt = now() + OTP_TTL_MS;
    otpSession.attempts = 0;
    otpSession.verified = false;

    await sendSms(phoneNumber, `Your verification code is: ${otp}. It expires in 5 minutes.`);

    return res.json({ success: true, message: 'Verification code sent' });
  } catch (error) {
    return res.status(500).json({ error: 'Failed to send verification code' });
  }
});

app.post('/auth/2fa/verify', (req, res) => {
  const { userId, code } = req.body;

  if (!userId || !code) {
    return res.status(400).json({ error: 'userId and code are required' });
  }

  const otpSession = ensureAuthSession(req);

  if (
    !otpSession.userId ||
    !otpSession.otpHash ||
    !otpSession.salt ||
    !otpSession.expiresAt
  ) {
    return res.status(400).json({ error: 'No active verification challenge' });
  }

  if (String(otpSession.userId) !== String(userId)) {
    return res.status(400).json({ error: 'Invalid verification challenge' });
  }

  if (otpSession.verified) {
    return res.json({ success: true, message: 'Already verified' });
  }

  if (now() > otpSession.expiresAt) {
    delete req.session.otp;
    return res.status(400).json({ error: 'Code expired' });
  }

  otpSession.attempts = (otpSession.attempts || 0) + 1;

  if (otpSession.attempts > MAX_VERIFY_ATTEMPTS) {
    delete req.session.otp;
    return res.status(429).json({ error: 'Too many attempts' });
  }

  const candidateHash = hashOtp(String(code), otpSession.salt);

  if (crypto.timingSafeEqual(Buffer.from(candidateHash), Buffer.from(otpSession.otpHash))) {
    otpSession.verified = true;
    return res.json({ success: true, message: 'Verification successful' });
  }

  return res.status(400).json({ error: 'Invalid code' });
});

app.get('/auth/2fa/status', (req, res) => {
  const otpSession = ensureAuthSession(req);

  return res.json({
    active: !!otpSession.userId,
    verified: !!otpSession.verified,
    expiresAt: otpSession.expiresAt || null,
    attempts: otpSession.attempts || 0
  });
});

app.post('/auth/2fa/reset', (req, res) => {
  delete req.session.otp;
  return res.json({ success: true });
});

app.get('/protected', (req, res) => {
  const otpSession = ensureAuthSession(req);

  if (!otpSession.verified) {
    return res.status(401).json({ error: '2FA required' });
  }

  return res.json({ success: true, message: 'Access granted to protected resource' });
});

